exports.clearAnonymousUsers = functions.https.onRequest((req, res) => {
  cors(req, res, async () => {
    try {
      const authenticatedUser = await getAuthenticatedUser(req);
      const context = { auth: { uid: authenticatedUser.uid } };
      await isAuthenticatedAdmin(context);

      const usersRef = db.collection('users');
      // Query for documents where the email field is missing or null
      // Firestore does not directly support 'is null' or 'field does not exist' in queries.
      // A common workaround is to query for a field that *does* exist in non-anonymous users,
      // or to mark anonymous users in a specific way.
      // Assuming anonymous users might have no 'email' field or an empty string email.
      // For a robust solution, it's better to explicitly mark anonymous users on creation.
      // Here, we'll try to find documents where the 'email' field is explicitly null or an empty string.

      // Option 1: Query for email == null (if set as null)
      const nullEmailSnapshot = await usersRef.where('email', '==', null).get();

      // Option 2: Query for email == '' (if set as empty string)
      const emptyEmailSnapshot = await usersRef.where('email', '==', '').get();

      // Option 3: Query for documents that do NOT have the 'email' field.
      // This is not directly supported by Firestore. You would need to fetch all users
      // and filter client-side, or have a specific field like `isAnonymous: true`.
      // For now, we combine null and empty string checks which should cover most cases
      // if anonymous users' documents are created with `email: null` or `email: ''`.

      const batch = db.batch();
      let deletedCount = 0;

      nullEmailSnapshot.docs.forEach(doc => {
        batch.delete(doc.ref);
        deletedCount++;
      });

      emptyEmailSnapshot.docs.forEach(doc => {
        // Avoid double-deleting if a doc somehow appears in both
        if (!batch.docs.has(doc.ref.path)) { // This is a conceptual check, batch.docs is not directly accessible like this.
                                            // A Set of doc.id would be needed for perfect deduplication, but unlikely with `null` vs `''`.
          batch.delete(doc.ref);
          deletedCount++;
        }
      });

      // A more robust way to handle 'field does not exist' would be to add a field
      // like 'isAnonymous: true' during anonymous user creation in useAuth.js.
      // For now, this approach attempts to catch users with explicitly null/empty emails.

      await batch.commit();
      res.status(200).json({ message: `Successfully deleted ${deletedCount} anonymous user documents.` });
    } catch (error) {
      console.error("Error in clearAnonymousUsers:", error);
      res.status(500).send('An error occurred in clearAnonymousUsers.');
    }
  });
});

